/**
 * 应用设置页面
 * API密钥管理、模型选择、温度参数、主题切换、自动保存间隔
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Form,
  Input,
  Select,
  Slider,
  Switch,
  Button,
  Space,
  Divider,
  message,
  Alert,
  Tabs,
  Tag,
  Tooltip,
  InputNumber,
  List,
  Modal,
} from 'antd'
import {
  KeyOutlined,
  SaveOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  ApiOutlined,
  SettingOutlined,
  ExperimentOutlined,
} from '@ant-design/icons'

// 可用的 AI 服务
const AI_SERVICES = [
  { value: 'deepseek', label: 'DeepSeek', models: ['deepseek-chat', 'deepseek-reasoner'] },
  { value: 'doubao', label: '豆包 (Doubao)', models: ['doubao-pro', 'doubao-lite', 'doubao-mini'] },
]

// 主题选项
const THEME_OPTIONS = [
  { value: 'light', label: '浅色' },
  { value: 'dark', label: '深色' },
  { value: 'system', label: '跟随系统' },
]

interface AppSettings {
  // AI 设置
  aiServices: Record<string, { apiKey: string; model: string; temperature: number; enabled: boolean }>
  // 自动保存
  autoSaveInterval: number // 秒
  autoSaveEnabled: boolean
  // 外观
  theme: string
  editorFontSize: number
  editorLineHeight: number
}

const DEFAULT_SETTINGS: AppSettings = {
  aiServices: {
    deepseek: { apiKey: '', model: 'deepseek-chat', temperature: 0.7, enabled: true },
    doubao: { apiKey: '', model: 'doubao-pro', temperature: 0.8, enabled: false },
  },
  autoSaveInterval: 5,
  autoSaveEnabled: true,
  theme: 'light',
  editorFontSize: 16,
  editorLineHeight: 1.8,
}

const AppSettingsPage: React.FC = () => {
  const [form] = Form.useForm<AppSettings>()
  const [saving, setSaving] = useState(false)
  const [testingService, setTestingService] = useState<string | null>(null)
  const [testResult, setTestResult] = useState<Record<string, boolean>>({})

  // 加载设置
  const loadSettings = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('appSettings', DEFAULT_SETTINGS)
      if (result.success && result.value) {
        form.setFieldsValue(result.value as AppSettings)
      } else {
        form.setFieldsValue(DEFAULT_SETTINGS)
      }
    } catch (error) {
      form.setFieldsValue(DEFAULT_SETTINGS)
    }
  }

  useEffect(() => {
    loadSettings()
  }, [])

  // 保存设置
  const handleSave = async () => {
    try {
      const values = form.getFieldsValue()
      setSaving(true)

      // 检查是否有 API key 需要加密保存
      for (const [service, config] of Object.entries(values.aiServices || {})) {
        if (config.apiKey && !config.apiKey.startsWith('encrypted:')) {
          // 加密保存
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const encFn = window.electronAPI.safeStorage.encrypt as (text: string) => Promise<{ success: boolean; data?: Uint8Array; error?: string }>
            const encResult = await encFn(config.apiKey)
            if (encResult.success && encResult.data) {
              // 将 Uint8Array 转为 base64 字符串存储
              const base64 = btoa(String.fromCharCode(...encResult.data))
              values.aiServices[service].apiKey = `encrypted:${base64}`
            }
          } catch (e) {
            console.warn('API key 加密失败，将以明文保存（不推荐）:', e)
          }
        }
      }

      await window.electronAPI.ai.saveSetting('appSettings', values)
      message.success('设置已保存')
    } catch (error) {
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  // 测试连接
  const handleTestConnection = async (service: string) => {
    setTestingService(service)
    setTestResult(prev => ({ ...prev, [service]: false }))
    try {
      const result = await window.electronAPI.ai.testConnection(service)
      setTestResult(prev => ({ ...prev, [service]: !!(result.success && result.result) }))
      if (result.success && result.result) {
        message.success(`${service} 连接成功`)
      } else {
        message.error(`${service} 连接失败: ${result.error}`)
      }
    } catch (error) {
      setTestResult(prev => ({ ...prev, [service]: false }))
      message.error(`${service} 连接失败`)
    } finally {
      setTestingService(null)
    }
  }

  // 验证 API Key 格式（解密显示）
  const getDisplayApiKey = (apiKey: string) => {
    if (!apiKey) return ''
    if (apiKey.startsWith('encrypted:')) {
      return '••••••••（已加密）'
    }
    if (apiKey.length > 8) {
      return apiKey.slice(0, 4) + '••••••••' + apiKey.slice(-4)
    }
    return apiKey
  }

  const values = form.getFieldsValue()

  return (
    <div
      style={{
        maxWidth: 800,
        margin: '0 auto',
        padding: 24,
        overflow: 'auto',
        height: '100%',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 24,
        }}
      >
        <h2 style={{ margin: 0 }}>⚙️ 应用设置</h2>
        <Button
          type="primary"
          icon={<SaveOutlined />}
          loading={saving}
          onClick={handleSave}
        >
          保存设置
        </Button>
      </div>

      <Form
        form={form}
        layout="vertical"
        initialValues={DEFAULT_SETTINGS}
      >
        <Tabs
          items={[
            {
              key: 'ai',
              label: <span><ApiOutlined /> AI 服务</span>,
              children: (
                <div>
                  {AI_SERVICES.map(service => (
                    <Card
                      key={service.value}
                      size="small"
                      title={
                        <Space>
                          {service.label}
                          <Tag color={values.aiServices?.[service.value]?.enabled ? 'green' : 'default'}>
                            {values.aiServices?.[service.value]?.enabled ? '已启用' : '未启用'}
                          </Tag>
                        </Space>
                      }
                      style={{ marginBottom: 16 }}
                      extra={
                        <Switch
                          checked={values.aiServices?.[service.value]?.enabled}
                          onChange={(checked) => {
                            form.setFieldsValue({
                              ['aiServices']: {
                                [service.value]: {
                                  enabled: checked,
                                },
                              },
                            })
                          }}
                        />
                      }
                    >
                      <Form.Item
                        label="API Key"
                        name={['aiServices', service.value, 'apiKey']}
                        extra={
                          values.aiServices?.[service.value]?.apiKey && (
                            <Tag style={{ marginTop: 4 }}>
                              {getDisplayApiKey(values.aiServices?.[service.value]?.apiKey || '')}
                            </Tag>
                          )
                        }
                      >
                        <Input.Password
                          placeholder={
                            service.value === 'deepseek'
                              ? 'sk-xxxxxxxxxxxxxxxx'
                              : '输入 API Key'
                          }
                        />
                      </Form.Item>

                      <Form.Item
                        label="模型"
                        name={['aiServices', service.value, 'model']}
                      >
                        <Select
                          options={service.models.map(m => ({ value: m, label: m }))}
                          style={{ width: 200 }}
                        />
                      </Form.Item>

                      <Form.Item
                        label={
                          <Tooltip title="Temperature 控制创造性：0.0-0.3 更确定性，0.7-1.0 更有创意">
                            Temperature（创造性）
                          </Tooltip>
                        }
                        name={['aiServices', service.value, 'temperature']}
                      >
                        <Slider
                          min={0}
                          max={1}
                          step={0.1}
                          marks={{
                            0: '精准',
                            0.5: '平衡',
                            1: '创意',
                          }}
                          style={{ width: 300 }}
                        />
                      </Form.Item>

                      <Button
                        size="small"
                        icon={
                          testResult[service.value] ? (
                            <CheckCircleOutlined style={{ color: '#52c41a' }} />
                          ) : testResult[service.value] === false ? (
                            <CloseCircleOutlined style={{ color: '#ff4d4f' }} />
                          ) : undefined
                        }
                        onClick={() => handleTestConnection(service.value)}
                        loading={testingService === service.value}
                      >
                        测试连接
                      </Button>
                    </Card>
                  ))}

                  <Alert
                    message="API Key 安全说明"
                    description="API Key 将使用系统安全存储（SafeStorage）加密保存，不会以明文形式存储在配置文件中。"
                    type="info"
                    showIcon
                  />
                </div>
              ),
            },
            {
              key: 'editor',
              label: <span><ExperimentOutlined /> 编辑器</span>,
              children: (
                <div>
                  <Card size="small" title="自动保存" style={{ marginBottom: 16 }}>
                    <Form.Item
                      label="启用自动保存"
                      name="autoSaveEnabled"
                      valuePropName="checked"
                    >
                      <Switch />
                    </Form.Item>

                    <Form.Item
                      label="自动保存间隔（秒）"
                      name="autoSaveInterval"
                    >
                      <Slider
                        min={1}
                        max={30}
                        marks={{ 3: '3秒', 5: '5秒', 10: '10秒', 30: '30秒' }}
                        disabled={!values.autoSaveEnabled}
                      />
                    </Form.Item>
                  </Card>

                  <Card size="small" title="编辑器外观">
                    <Form.Item
                      label="字体大小"
                      name="editorFontSize"
                    >
                      <Slider
                        min={12}
                        max={24}
                        marks={{ 14: '14', 16: '16', 18: '18', 20: '20' }}
                      />
                    </Form.Item>

                    <Form.Item
                      label="行高"
                      name="editorLineHeight"
                    >
                      <Slider
                        min={1.2}
                        max={2.5}
                        step={0.1}
                        marks={{ 1.6: '1.6', 1.8: '1.8', 2.0: '2.0' }}
                      />
                    </Form.Item>
                  </Card>
                </div>
              ),
            },
            {
              key: 'appearance',
              label: <span><SettingOutlined /> 外观</span>,
              children: (
                <Card size="small" title="主题设置">
                  <Form.Item
                    label="主题"
                    name="theme"
                  >
                    <Select options={THEME_OPTIONS} style={{ width: 200 }} />
                  </Form.Item>

                  <Alert
                    message="深色主题切换需要重启应用生效"
                    type="warning"
                    showIcon
                    style={{ marginTop: 8 }}
                  />
                </Card>
              ),
            },
          ]}
        />
      </Form>
    </div>
  )
}

export default AppSettingsPage
